from sys import stdin

def read_list_str():
    return stdin.readline().strip().split()


def read_list_int():
    return list(map(int, read_list_str()))


def read_int():
    return int(read_list_str()[0])


def read_str():
    return stdin.readline().strip()


def solve(name):
    current_letter = 'a'
    min_rotations = 0
    for letter in name:
        if letter < current_letter:
            min_rotations += 26
        min_rotations += ord(letter) - ord(current_letter)
        current_letter = letter
    return min_rotations


if __name__ == '__main__':
    name = read_str()
    print(solve(name))
